import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/admin-dashboard.css';
import '../../styles/admin-layout.css';

export const AdminDashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      setLoading(true);
      const response = await adminService.getSystemStats();
      // response.data = { success: true, data: {...} }
      // So we need response.data.data to get the actual stats
      setStats(response.data.data);
    } catch (err) {
      setError('Lỗi tải dữ liệu thống kê');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center admin-dashboard__loading-container">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }
  const cardsConfig = [
    { key: 'total_users', label: 'Tổng người dùng', icon: '👥', className: 'admin-dashboard__stat-icon--users' },
    { key: 'total_ponds', label: 'Tổng ao nuôi', icon: '🏞️', className: 'admin-dashboard__stat-icon--ponds' },
    { key: 'total_seasons', label: 'Tổng mùa vụ', icon: '🌾', className: 'admin-dashboard__stat-icon--seasons' },
    { key: 'active_seasons', label: 'Mùa vụ hoạt động', icon: '📊', className: 'admin-dashboard__stat-icon--active-seasons' },
  ];

  const availableCards = cardsConfig.filter((c) => stats && stats[c.key] !== undefined && stats[c.key] !== null);

  return (
    <div className="dashboard admin-page">
      <div className="dashboard-header">
        <h1>🔐 Bảng điều khiển quản lý</h1>
        <p>Tổng quan hệ thống quản lý ao tôm thông minh</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      {availableCards.length > 0 ? (
        <div className="stats-grid">
          {availableCards.map((c) => (
            <div className="stat-card" key={c.key}>
              <div className={`stat-icon ${c.className}`} aria-hidden>
                {c.icon}
              </div>
              <div className="stat-content">
                <p className="stat-label">{c.label}</p>
                <p className="stat-value">{stats[c.key]}</p>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="card">
          <h2>Không có dữ liệu tổng quan</h2>
          <p>Không có chỉ số thống kê nào được cấu hình cho frontend hiện tại.</p>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
